            break
        elif maps[y][x] == "#":
            break
        elif maps[y][x] == "O":
            return True
    y -= dy[mode]
    x -= dx[mode]
    return y,x

def left(by,bx,ry,rx):
    if bx < rx:
        blue = move(0, by, bx)

        if blue == True:
            return False
        maps[blue[0]][blue[1]] = "#"
        red = move(0, ry, rx)
        maps[blue[0]][blue[1]] = "."

        if red == True:
            return True

    else:
        red = move(0, ry, rx)

        if red == True:
            p = move(0, by, bx)
            if p == True:
                return False
            else:
                return True

        maps[red[0]][red[1]] = "#"
        blue = move(0, by, bx)
        maps[red[0]][red[1]] = "."

        if blue == True:
            return False

    return [blue[0], blue[1], red[0], red[1]]

def right(by,bx,ry,rx):
    if bx > rx:
        blue = move(1, by, bx)

        if blue == True:
            return False
        maps[blue[0]][blue[1]] = "#"
        red = move(1, ry, rx)
        maps[blue[0]][blue[1]] = "."

        if red == True:
            return True

