    distance[start] = 0

    q = []
    heapq.heappush(q,[distance[start],start])

    while q:
        d,cur = heapq.heappop(q)

        if d > distance[cur]:
            continue

        for next_node, nd in node_info[cur]:
            new_distance = d + nd
            if distance[next_node] > new_distance:
                heapq.heappush(q, [new_distance, next_node])
                distance[next_node] = new_distance

    for i in distance:
        if distance[i] <= M:
            result += items[i]
    return result

