    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]
    coord_set = set(tuple(coord) for coord in coords)
    start = tuple(coords[0])
    stack = [start]
    visited = set([start])

    while stack:
        current = stack.pop()
        for d in directions:
            neighbor = (current[0] + d[0], current[1] + d[1])
            if neighbor in coord_set and neighbor not in visited:
                visited.add(neighbor)
